```cpp
#include <unistd.h>
#include <iostream>
#include <cstdio>

int main() {
    int fd[2];
    pipe(fd);  // Create a pipe to connect the process

    pid_t pid = fork();  // Fork a new process

    if (pid == -1) {
        // Error handling
        std::cerr << "Fork failed" << std::endl;
        return 1;
    } else if (pid == 0) {
        // Child process
        close(fd[1]);  // Close the write end of the pipe
        dup2(fd[0], STDIN_FILENO);  // Redirect stdin to the pipe
        dup2(fd[0], STDOUT_FILENO);  // Redirect stdout to the pipe
        close(fd[0]);  // Close the duplicate file descriptors

        // Execute a command or do something else
        execlp("some_command", "some_command", NULL);
        std::cerr << "execlp failed" << std::endl;
        _exit(1);
    } else {
        // Parent process
        close(fd[0]);  // Close the read end of the pipe
        // Do something with the child process, e.g., wait for it to finish
        wait(NULL);
    }

    return 0;
}
```

In this example, the child process has its standard input and output redirected to the pipe. The parent process can read from the read end of the pipe and write to the write end if needed. Adjust the `execlp` call to the command or program you want to run in the child process.

